content:
## 来源

{{ source }}

## 世界

- id: {{ world.id }}
- 名称: {{ world.name }}
- 描述: {{ world.description }}
- language: {{ world.language }}

## 模拟

- id: {{ simulation.id }}
- 当前时间: {{ simulation.current_time }}

## 用户输入

{{ user_input }}

## 用户角色 id

{{ user_character_id }}

## 要提交的已接受行动

{% for entry in coordination_result.accepted_actions %}
accepted:{{ loop.index0 }}:
- actor id: {{ entry.actor_id }}
- original action index: {{ entry.action_index }}
- start offset seconds: {{ entry.start_offset_seconds }}
- end offset seconds: {{ entry.end_offset_seconds }}
- summary: {{ entry.summary }}
- action type: {{ entry.action.type }}
- label: {{ entry.action.label }}
- target ids: {{ entry.action.target_ids }}
- utterance: {{ entry.action.utterance }}
- expected effects: {{ entry.action.expected_effects }}
{% else %}
- 无
{% endfor %}

## 协调状态

- status: {{ coordination_result.status }}
- stopped reason: {{ coordination_result.stopped_reason }}

{% if coordination_result.problem %}
Problem:
- type: {{ coordination_result.problem.type }}
- involved actor ids: {{ coordination_result.problem.involved_actor_ids }}
- description: {{ coordination_result.problem.description }}
{% endif %}

## 执行已接受行动的角色

{% for entry in actors %}
- actor id: {{ entry.actor.id }}; 姓名: {{ entry.actor.name }}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}; 公开状态: {{ entry.actor.public_state }}; 私密状态: {{ entry.actor.private_state }}; 当前活动: {{ entry.actor.current_activity.name }}; 活动可打断: {{ entry.actor.current_activity.interruptible }}
  库存:
{% for item in entry.inventory %}
  - stack id: {{ item.stack_id }}; item id: {{ item.item_id }}; {{ item.name }} x{{ item.quantity }}{% if item.quality %}; 品质: {{ item.quality }}{% endif %}; owner id: {{ item.owner_id }}; 描述: {{ item.description }}
{% else %}
  - 无
{% endfor %}
  装备:
{% for equipment in entry.equipment %}
  - id: {{ equipment.id }}; {{ equipment.name }}; 已装备: {{ equipment.equipped }}{% if equipment.equipped_position %}; 部位: {{ equipment.equipped_position }}{% endif %}; 描述: {{ equipment.description }}{% if equipment.quality %}; 品质: {{ equipment.quality }}{% endif %}
{% else %}
  - 无
{% endfor %}
{% else %}
- 无
{% endfor %}

## 附近普通角色

{% for entry in nearby_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.landmark %}; 地标: {{ entry.landmark.name }}{% endif %}; 公开状态: {{ entry.character.public_state }}; 当前活动: {{ entry.character.current_activity.name }}; 描述: {{ entry.character.description }}
{% else %}
- 无
{% endfor %}

## 附近背景角色

{% for entry in nearby_background_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.landmark %}; 地标: {{ entry.landmark.name }}{% endif %}; 描述: {{ entry.character.description }}
{% else %}
- 无
{% endfor %}

## 附近物品堆叠

{% for entry in nearby_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}{% if entry.stack.quality %}; 品质: {{ entry.stack.quality }}{% endif %}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.item.description }}
{% else %}
- 无
{% endfor %}

## 附近装备

{% for entry in nearby_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.equipment.description }}{% if entry.equipment.quality %}; 品质: {{ entry.equipment.quality }}{% endif %}
{% else %}
- 无
{% endfor %}

## 附近容器

{% for entry in nearby_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}; location id: {{ entry.location.id }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.container.description }}
{% else %}
- 无
{% endfor %}

## 附近地标

{% for landmark in nearby_landmarks %}
- id: {{ landmark.id }}; {{ landmark.name }}; 描述: {{ landmark.description }}
{% else %}
- 无
{% endfor %}
